//! MS-OI29500 implementation note tests: Tables (§17.4) and Table Styles (§17.7.6)
//!
//! These tests encode correct Microsoft Word behavior as documented in MS-OI29500,
//! which often differs from the base ISO 29500-1 standard.
//!
//! Fixture DOCX files are generated by `testdata/spec-compliance/create_docs.py`.

use stemma::{BlockNode, CanonDoc, InlineNode, TableNode};

use crate::common;

const FIXTURES: &str = "testdata/spec-compliance/ms-tables";

// ── helpers ──────────────────────────────────────────────────────────────
fn first_table(doc: &CanonDoc) -> &TableNode {
    doc.blocks
        .iter()
        .find_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .expect("document should contain at least one table")
}

fn all_tables(doc: &CanonDoc) -> Vec<&TableNode> {
    doc.blocks
        .iter()
        .filter_map(|b| match &b.block {
            BlockNode::Table(t) => Some(t.as_ref()),
            _ => None,
        })
        .collect()
}

fn cell_first_text_node(table: &TableNode, row: usize, col: usize) -> &stemma::TextNode {
    let cell = &table.rows[row].cells[col];
    for block in &cell.blocks {
        if let BlockNode::Paragraph(p) = block {
            for inline in p.all_inlines() {
                if let InlineNode::Text(t) = inline {
                    return t;
                }
            }
        }
    }
    panic!("cell ({row},{col}) should contain at least one text node")
}

fn cell_first_paragraph(table: &TableNode, row: usize, col: usize) -> &stemma::ParagraphNode {
    let cell = &table.rows[row].cells[col];
    cell.blocks
        .iter()
        .find_map(|b| match b {
            BlockNode::Paragraph(p) => Some(p),
            _ => None,
        })
        .expect("cell should contain at least one paragraph")
}

// ── 1) tblLook val attribute fallback (§17.4.55(c)) ─────────────────────

/// MS-OI29500 §17.4.55(c): Word reads the val attribute from the tblLook element
/// if, and only if, none of the individual attributes (firstRow, lastRow,
/// firstColumn, lastColumn, noHBand, noVBand) are present.
///
/// Fixture: tblLook has only w:val="0020" (firstRow=1, noHBand=0).
/// Our parser only reads individual attributes → gets all-false TblLook.
#[test]
fn ms_tbllook_val_fallback_firstrow_applies() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-val-fallback");
    let table = first_table(&doc);

    // Row 0: firstRow conditional should apply blue shading (from val bitmask)
    let shading_00 = table.rows[0].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,0) should have shading from firstRow (parsed from val bitmask)");
    assert_eq!(
        shading_00.fill.as_deref(),
        Some("4472C4"),
        "cell (0,0): firstRow blue (4472C4) from val=0020 bitmask"
    );
}

/// MS-OI29500 §17.4.55(c): With val="0020", noHBand=0 so banding would apply
/// if the style had a band size. But this fixture's style has no
/// tblStyleRowBandSize, and per MS-OI29500 §17.7.6.7 the default is 0 (no
/// banding). Verify that data rows have NO band shading.
#[test]
fn ms_tbllook_val_fallback_banding_enabled() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-val-fallback");
    let table = first_table(&doc);

    // Data rows: noHBand=0 from val bitmask, but band size defaults to 0 (§17.7.6.7),
    // so no banding is applied.
    assert!(
        table.rows[1].cells[0].formatting.shading.is_none(),
        "cell (1,0): no banding shading (band size absent → default 0)"
    );
    assert!(
        table.rows[2].cells[0].formatting.shading.is_none(),
        "cell (2,0): no banding shading (band size absent → default 0)"
    );
}

// ── 2) tblLook omitted → default 0x04A0 (§17.4.55(a)) ──────────────────

/// MS-OI29500 §17.4.55(a): When tblLook is omitted entirely, Word assumes
/// a bitmask of 0x04A0 = firstRow=1, firstColumn=1, noVBand=1 (noHBand=0).
///
/// Our parser defaults all flags to false → firstRow conditional is skipped.
#[test]
fn ms_tbllook_omitted_default_firstrow_applies() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-omitted-default");
    let table = first_table(&doc);

    // With MS default 0x04A0, firstRow=1 → row 0 gets firstRow blue shading
    let shading_00 = table.rows[0].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,0) should have shading from firstRow (default 0x04A0)");
    assert_eq!(
        shading_00.fill.as_deref(),
        Some("4472C4"),
        "cell (0,0): firstRow blue (4472C4) from default tblLook 0x04A0"
    );
}

/// MS-OI29500 §17.4.55(a): With default 0x04A0, firstColumn=1 so column-0
/// data rows get firstCol conditional shading. Non-first-column data cells
/// get no banding because band size defaults to 0 (MS-OI29500 §17.7.6.7).
#[test]
fn ms_tbllook_omitted_default_no_banding() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tbllook-omitted-default");
    let table = first_table(&doc);

    // 0x04A0 has firstColumn=1, so column-0 data rows get firstCol shading.
    // Non-first-column cells should have no shading: noHBand=0 but band size
    // defaults to 0 (§17.7.6.7), so banding doesn't apply either.
    assert!(
        table.rows[1].cells[1].formatting.shading.is_none(),
        "cell (1,1): no shading (noHBand=0 but band size=0, not firstCol)"
    );
    assert!(
        table.rows[2].cells[1].formatting.shading.is_none(),
        "cell (2,1): no shading (noHBand=0 but band size=0, not firstCol)"
    );
}

// ── 3) Conditional formatting precedence order (§17.7.6(c)) ─────────────

/// MS-OI29500 §17.7.6(c) / §17.7.6.6(a): Office applies conditional formats
/// in this order (later overrides earlier):
///   1. band rows, band cols
///   2. firstCol, lastCol
///   3. firstRow, lastRow
///   4. corners
///
/// At corner cell (0,0), firstRow should WIN over firstCol because
/// firstRow has higher precedence in MS order. Our code currently gives
/// firstCol higher precedence.
#[test]
fn ms_conditional_precedence_firstrow_wins_over_firstcol() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence-order");
    let table = first_table(&doc);

    // Cell (0,0): firstRow blue (4472C4) should win over firstCol green (70AD47)
    let shading_00 = table.rows[0].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,0) should have shading");
    assert_eq!(
        shading_00.fill.as_deref(),
        Some("4472C4"),
        "cell (0,0): firstRow blue (4472C4) should win over firstCol green (70AD47) per MS precedence"
    );
}

/// MS-OI29500 §17.7.6(c): Cell (0,2) — firstRow should win over lastCol.
#[test]
fn ms_conditional_precedence_firstrow_wins_over_lastcol() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence-order");
    let table = first_table(&doc);

    let shading_02 = table.rows[0].cells[2]
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,2) should have shading");
    assert_eq!(
        shading_02.fill.as_deref(),
        Some("4472C4"),
        "cell (0,2): firstRow blue wins over lastCol purple per MS precedence"
    );
}

/// MS-OI29500 §17.7.6(c): Cell (3,0) — lastRow should win over firstCol.
#[test]
fn ms_conditional_precedence_lastrow_wins_over_firstcol() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence-order");
    let table = first_table(&doc);

    let shading_30 = table.rows[3].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("cell (3,0) should have shading");
    assert_eq!(
        shading_30.fill.as_deref(),
        Some("ED7D31"),
        "cell (3,0): lastRow orange (ED7D31) should win over firstCol green (70AD47)"
    );
}

/// MS-OI29500 §17.7.6(c): Cell (1,0) — firstCol applies (no row conditional).
#[test]
fn ms_conditional_precedence_firstcol_on_data_row() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "conditional-precedence-order");
    let table = first_table(&doc);

    let shading_10 = table.rows[1].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("cell (1,0) should have shading from firstCol");
    assert_eq!(
        shading_10.fill.as_deref(),
        Some("70AD47"),
        "cell (1,0): firstCol green (70AD47)"
    );
}

// ── 4) Corner cell conditional formatting (§17.4.54/§17.4.55) ───────────

/// MS-OI29500 §17.4.54(a)/§17.4.55(b)/§17.7.6(a): Corner cells (nwCell,
/// neCell, swCell, seCell) have the HIGHEST precedence and override even
/// firstRow/lastRow/firstCol/lastCol.
///
#[test]
fn ms_corner_cell_nw_overrides_firstrow() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "corner-cell-conditional");
    let table = first_table(&doc);

    // Cell (0,0): nwCell red (FF0000) should override firstRow blue and firstCol green
    let shading_00 = table.rows[0].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,0) should have shading from nwCell corner conditional");
    assert_eq!(
        shading_00.fill.as_deref(),
        Some("FF0000"),
        "cell (0,0): nwCell red (FF0000) should override firstRow and firstCol"
    );
}

/// MS-OI29500 §17.7.6(a): seCell (bottom-right corner) overrides lastRow/lastCol.
#[test]
fn ms_corner_cell_se_overrides_lastrow() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "corner-cell-conditional");
    let table = first_table(&doc);

    // Cell (2,2): seCell yellow (FFFF00)
    let shading_22 = table.rows[2].cells[2]
        .formatting
        .shading
        .as_ref()
        .expect("cell (2,2) should have shading from seCell corner conditional");
    assert_eq!(
        shading_22.fill.as_deref(),
        Some("FFFF00"),
        "cell (2,2): seCell yellow (FFFF00) should override lastRow and lastCol"
    );
}

// ── 5) Toggle property reset in table styles (§17.7.6(b)) ──────────────

/// MS-OI29500 §17.7.6(b): Word resets toggle property values in table styles
/// instead of XOR toggling with the inherited value.
///
/// Cell (0,0) paragraph style sets bold=true. Table style firstRow also
/// sets bold=true. Under XOR: true XOR true = false. Under MS reset: true.
#[test]
fn ms_toggle_reset_bold_stays_true() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "toggle-reset-in-table-style");
    let table = first_table(&doc);

    // Cell (0,0): bold should be true (MS reset behavior)
    let text_00 = cell_first_text_node(table, 0, 0);
    assert!(
        text_00.marks.contains(&stemma::Mark::Bold),
        "cell (0,0): text should be bold (MS reset behavior, not XOR toggle)"
    );
}

// ── 6) Border conflict weight calculation (§17.4.66(a)) ─────────────────

/// MS-OI29500 §17.4.66(a): Border conflict resolution uses weight formula:
/// weight = border_width_eighths * border_number.
/// Border numbers: single=1, thick=2, double=3, etc.
/// Dotted/dashed styles always get weight 1.
///
/// Table has thick red single borders (sz=24). Cell (0,0) has thin blue
/// double (sz=4). Single weight=24*1=24, double weight=4*3=12 -> single wins.
#[test]
fn ms_border_conflict_weight_single_wins() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-conflict-weight");
    let table = first_table(&doc);

    // Cell (0,0): thin double (4*3=12) LOSES to table single (24*1=24).
    // After conflict resolution, the table's red single border replaces
    // the cell's blue double border.
    let cell_00 = &table.rows[0].cells[0];
    let borders = cell_00
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,0) should have borders after conflict resolution");

    let top = borders.top.as_ref().expect("should have top border");
    assert_eq!(
        top.color.as_deref(),
        Some("FF0000"),
        "cell (0,0): table red single (weight 24) should win over cell blue double (weight 12)"
    );
    assert_eq!(
        top.style,
        stemma::domain::BorderStyle::Single,
        "winner should be single style"
    );
}

/// MS-OI29500 §17.4.66(a): Cell (0,1) wide double (sz=18, weight=54)
/// beats table single (sz=24, weight=24).
#[test]
fn ms_border_conflict_weight_double_wins() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "border-conflict-weight");
    let table = first_table(&doc);

    let cell_01 = &table.rows[0].cells[1];
    let borders = cell_01
        .formatting
        .borders
        .as_ref()
        .expect("cell (0,1) should have borders");

    let top = borders.top.as_ref().expect("should have top border");
    assert_eq!(
        top.color.as_deref(),
        Some("00FF00"),
        "cell (0,1): cell green double (weight 54) should win over table red single (weight 24)"
    );
    assert_eq!(
        top.style,
        stemma::domain::BorderStyle::Double,
        "winner should be double style"
    );
}

// ── 7) Cell margin type="nil" (§17.4.77(a)) ─────────────────────────────

/// MS-OI29500 §17.4.77(a): Word ignores cell margin elements when the
/// type attribute has a value of "nil". The cell falls back to the table's
/// default cell margins.
///
/// Cell (0,0): type="nil" → element ignored, should use table default 150tw.
/// Cell (0,1): type="dxa" w=0 → valid override, margins are 0.
#[test]
fn ms_cell_margin_type_nil_ignored() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-margin-type-nil");
    let table = first_table(&doc);

    // Cell (0,0): type="nil" should be ignored → falls back to table default 150tw
    // Currently our parser may treat nil as a valid value of 0.
    let cell_00 = &table.rows[0].cells[0];

    // The cell should NOT have per-cell margin override (nil means "ignore this element")
    // It should inherit the table default 150tw.
    // If margins are present, they should reflect the table default, not 0.
    if let Some(margins) = &cell_00.formatting.margins {
        assert_eq!(
            margins.top,
            Some(150),
            "cell (0,0): type=nil should be ignored → table default 150tw"
        );
    }
    // If margins are None, that's also acceptable if table defaults apply elsewhere
}

/// MS-OI29500 §17.4.77(a): Cell (0,1) type="dxa" w=0 is a valid override.
#[test]
fn ms_cell_margin_type_dxa_zero_valid() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "cell-margin-type-nil");
    let table = first_table(&doc);

    let cell_01 = &table.rows[0].cells[1];
    let margins = cell_01
        .formatting
        .margins
        .as_ref()
        .expect("cell (0,1) should have margin override with type=dxa w=0");
    assert_eq!(
        margins.top,
        Some(0),
        "cell (0,1): type=dxa w=0 → margins explicitly 0"
    );
}

// ── 8) tblInd not ignored with non-left justification (§17.4.50(a)) ─────

/// MS-OI29500 §17.4.50(a): The standard says tblInd is ignored if the
/// justification is not left. Word does NOT ignore tblInd regardless.
///
/// Table 1 has center justification + tblInd=720. Word still applies indent.
#[test]
fn ms_tblind_with_center_justification() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tblind-non-left-justification");
    let tables = all_tables(&doc);
    assert!(tables.len() >= 2, "should have at least 2 tables");

    // Table 1: center + indent=720
    assert_eq!(
        tables[0].formatting.indent,
        Some(720),
        "table 1: tblInd=720 should be preserved even with center justification"
    );
    assert_eq!(
        tables[0].formatting.alignment,
        Some(stemma::Alignment::Center),
        "table 1: alignment should be center"
    );
}

/// MS-OI29500 §17.4.50(a): Table 2 has right justification + tblInd=720.
#[test]
fn ms_tblind_with_right_justification() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "tblind-non-left-justification");
    let tables = all_tables(&doc);

    // Table 2: right + indent=720
    assert_eq!(
        tables[1].formatting.indent,
        Some(720),
        "table 2: tblInd=720 should be preserved even with right justification"
    );
    assert_eq!(
        tables[1].formatting.alignment,
        Some(stemma::Alignment::Right),
        "table 2: alignment should be right"
    );
}

// ── 9) Band size default 0 (§17.7.6.5/§17.7.6.7) ───────────────────────

/// MS-OI29500 §17.7.6.5(b,c) / §17.7.6.7(a,b): Word uses 0 as the default
/// for tblStyleRowBandSize / tblStyleColBandSize. When band size is 0,
/// Word does NOT apply any banded conditional formatting.
///
/// The standard says default is 1 (banding applies with size 1).
/// Our code currently treats absent band size as 1 → banding works.
#[test]
fn ms_band_size_zero_default_no_banding() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "band-size-zero-default");
    let table = first_table(&doc);

    // With MS default band size = 0, NO banding should be applied
    for row_idx in 0..4 {
        assert!(
            table.rows[row_idx].cells[0].formatting.shading.is_none(),
            "row {row_idx}: band size 0 (MS default) means no banding shading"
        );
    }
}

// ── 10) Row height hRule default (§17.4.80(a)) ──────────────────────────

/// MS-OI29500 §17.4.80(a): If the hRule attribute is omitted, its value
/// is assumed to be "atLeast" (not "auto" as the standard says).
///
/// Row 0: trHeight val=720 with no hRule → should be "atLeast".
/// Row 1: trHeight val=720 with hRule="exact" → should be "exact".
#[test]
fn ms_row_height_hrule_default_atleast() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "row-height-hrule-default");
    let table = first_table(&doc);

    // Row 0: hRule omitted → MS defaults to "atLeast"
    let height_0 = table.rows[0]
        .height
        .expect("row 0 should have height from trHeight val=720");
    assert_eq!(height_0, 720, "row 0 height should be 720");

    let rule_0 = table.rows[0]
        .height_rule
        .as_ref()
        .expect("row 0 should have height_rule");
    assert_eq!(
        *rule_0,
        stemma::domain::HeightRule::AtLeast,
        "row 0: omitted hRule should default to 'atLeast' (MS), not 'auto' (standard)"
    );
}

/// MS-OI29500 §17.4.80(a): Row 1 has explicit hRule="exact".
#[test]
fn ms_row_height_hrule_explicit_exact() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "row-height-hrule-default");
    let table = first_table(&doc);

    let rule_1 = table.rows[1]
        .height_rule
        .as_ref()
        .expect("row 1 should have height_rule");
    assert_eq!(
        *rule_1,
        stemma::domain::HeightRule::Exact,
        "row 1: explicit hRule='exact' should be preserved"
    );
}

// ── 11) overrideTableStyleFontSizeAndJustification (MS-DOCX §2.3.1) ────

/// MS-DOCX §2.3.1: When overrideTableStyleFontSizeAndJustification is
/// false (default), the default paragraph style's 11pt/12pt font size and
/// left justification do NOT override the table style's values.
///
/// Table style firstRow sets center alignment and 14pt font. Normal style
/// has 11pt and left. With default compat setting, table style wins.
#[test]
fn ms_override_table_style_font_size() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "override-table-style-font");
    let table = first_table(&doc);

    // Header row: font size should be 28 half-points (14pt) from table style,
    // NOT 22 (11pt) from Normal style
    let text_00 = cell_first_text_node(table, 0, 0);
    assert_eq!(
        text_00.style_props.font_size,
        Some(28),
        "cell (0,0): font_size should be 28 (14pt) from table style, not 22 (11pt) from Normal"
    );
}

/// MS-DOCX §2.3.1: Table style alignment should win over Normal's left.
#[test]
fn ms_override_table_style_justification() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "override-table-style-font");
    let table = first_table(&doc);

    // Header row: alignment should be center from table style, not left from Normal
    let para_00 = cell_first_paragraph(table, 0, 0);
    assert_eq!(
        para_00.align,
        Some(stemma::Alignment::Center),
        "cell (0,0): alignment should be center from table style, not left from Normal"
    );
}

// ── 12) Table shading applies to cell spacing only (§17.4.31(a)) ────────

/// MS-OI29500 §17.4.31(a): Table-level shading is applied only to the
/// cell spacing area of the table, NOT to the cells directly.
///
/// Cell (0,0) has explicit green shading. Other cells have no cell-level
/// shading. The table's red shading should only fill the gaps between cells.
#[test]
fn ms_table_shading_not_applied_to_cells() {
    let (_runtime, doc) = common::import_fixture(FIXTURES, "table-shading-cell-spacing");
    let table = first_table(&doc);

    // Cell (0,0): explicit green cell shading should be preserved
    let shading_00 = table.rows[0].cells[0]
        .formatting
        .shading
        .as_ref()
        .expect("cell (0,0) should have explicit green shading");
    assert_eq!(
        shading_00.fill.as_deref(),
        Some("00FF00"),
        "cell (0,0): explicit green cell shading"
    );

    // Cell (0,1): no cell-level shading (table shading only fills spacing gaps)
    assert!(
        table.rows[0].cells[1].formatting.shading.is_none(),
        "cell (0,1): no cell-level shading (table shading only fills cell spacing area)"
    );

    // Cell (1,0): no cell-level shading
    assert!(
        table.rows[1].cells[0].formatting.shading.is_none(),
        "cell (1,0): no cell-level shading (table shading only fills cell spacing area)"
    );
}
